// Find the handleSubmit function and replace with this:

const handleSubmit = async (e) => {
  e.preventDefault();

  if (!validateStep3()) return;

  setLoading(true);
  setError('');

  try {
    // Make sure ALL form data is included
    const completeDoctorData = {
      ...formData,
      // Ensure all fields are explicitly included
      name: formData.name,
      email: formData.email,
      password: formData.password,
      phone: formData.phone,
      dateOfBirth: formData.dateOfBirth,
      gender: formData.gender,
      specialization: formData.specialization,
      license: formData.license,
      experience: formData.experience,
      qualification: formData.qualification,
      hospital: formData.hospital,
      consultationFee: formData.consultationFee,
      availableDays: formData.availableDays,
      availableTime: formData.availableTime,
      address: formData.address,
      bio: formData.bio,
      profileImage: formData.profileImage
    };

    const user = await doctorSignup(completeDoctorData);
    console.log('Saved doctor data:', user); // Debug log
    alert('Registration successful! Please login.');
    onSwitchToLogin();
  } catch (error) {
    setError(error.message || 'Registration failed. Please try again.');
  } finally {
    setLoading(false);
  }
};
